  // Initialize cooldown timer
  cooldownRemaining = cooldownDuration;

  // Update cooldown timer every second
  setInterval(function() {
    cooldownRemaining -= 1000;
    if (cooldownRemaining <= 0) {
      // Cooldown has expired, reset timer
      cooldownRemaining = 0;
    }
  }, 1000);
